const now = new Date();
const hour = now.getHours();

// Calendário completo: 6 posts/dia
// 09h = REEL | 12h = STORY produto | 14h = CARROSSEL | 17h = STORY dica | 19h = STORY bastidor | 21h = STORY CTA noturno
const schedule = {
  9:  { type: 'reel',     crew_type: 'social_post', format: 'reel' },
  12: { type: 'story',    crew_type: 'social_post', format: 'story' },
  14: { type: 'carousel', crew_type: 'social_post', format: 'carousel' },
  17: { type: 'story',    crew_type: 'social_post', format: 'story' },
  19: { type: 'story',    crew_type: 'social_post', format: 'story' },
  21: { type: 'story',    crew_type: 'social_post', format: 'story_cta' }
};

if (!schedule[hour]) { return []; }

const reelThemes = [
  'before/after transformacao ambiente 3 produtos Aura Decore',
  'como montar canto zen em 60 segundos japandi',
  '5 objetos que transformam qualquer sala japandi',
  'unboxing e styling vaso ceramica flores secas',
  'tour pelo lar japandi inspiracao decoracao',
  'rotina matinal japandi canto cafe difusor planta'
];
const feedThemes = [
  'vaso de ceramica japandi wabi-sabi',
  'almofada de linho minimalista natural',
  'plantas secas pampas biofilia japandi',
  'bandeja de madeira organizacao elegante',
  'difusor de varetas bem-estar olfativo',
  'vela aromatica cera de coco ritual',
  'decoracao wabi-sabi imperfeicao beleza',
  'ambiente japandi completo harmonia lar'
];
const storyThemes = [
  'produto destaque semana swipe ver loja',
  'dica rapida 3 objetos atemporais japandi',
  'bastidor selecao novos produtos Aura Decore',
  'enquete decoracao japandi plantas secas vivas',
  'cliente Aura Decore compartilhe seu lar',
  'lancamento novo produto countdown'
];

const s = schedule[hour];
const themes = s.type === 'reel' ? reelThemes : (s.type === 'carousel' ? feedThemes : storyThemes);
const idx = Math.floor(Math.random() * themes.length);

return [{ json: { 
  theme: themes[idx], 
  hour,
  format: s.format,
  crew_type: s.crew_type
}}];
